atCapCatalog.query:
#graphql
  query LocationAddResourceLimitCatalog($first: Int!) {
    shop {
      resourceLimits {
        locationLimit
      }
    }
    locations(first: $first, includeInactive: true) {
      nodes {
        id
        name
        isActive
        isFulfillmentService
        isPrimary
      }
      pageInfo {
        hasNextPage
        endCursor
      }
    }
  }

